def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            term = (ratio ** j) / j
            if j % 2 == 0:
                term *= 1.5
            else:
                term *= 0.75
            score += term
        if capacity > 20 * item:
            score *= 0.3
        elif capacity > 10 * item:
            score *= 0.6
        elif capacity > 5 * item:
            score *= 0.8
        else:
            score *= 1.2
        if score < 0.1:
            score += 0.05
        if i % 3 == 0:
            score *= 1.1
        elif i % 5 == 0:
            score *= 0.9
        if capacity < item * 0.5:
            score *= 2
        elif capacity < item * 0.75:
            score *= 1.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if np.isinf(priorities[i]):
            priorities[i] = max_priority * 15
    for i in range(len(priorities)):
        if priorities[i] < 0.05:
            priorities[i] = 0.05
    return priorities
